  3580 | static std::optional<std::pair<Value*, Value*>>
  3581 | getInvertibleOperands(const Operator *Op1,
  3582 |                       const Operator *Op2) {
  3583 |   if (Op1->getOpcode() != Op2->getOpcode())
  3584 |     return std::nullopt;
  3585 | 
  3586 |   auto getOperands = [&](unsigned OpNum) -> auto {
  3587 |     return std::make_pair(Op1->getOperand(OpNum), Op2->getOperand(OpNum));
  3588 |   };
  3589 | 
  3590 |   switch (Op1->getOpcode()) {
  3591 |   default:
  3592 |     break;
  3593 |   case Instruction::Or:
  3594 |     if (!cast<PossiblyDisjointInst>(Op1)->isDisjoint() ||
  3595 |         !cast<PossiblyDisjointInst>(Op2)->isDisjoint())
  3596 |       break;
  3597 |     [[fallthrough]];
  3598 |   case Instruction::Xor:
  3599 |   case Instruction::Add: {
  3600 |     Value *Other;
  3601 |     if (match(Op2, m_c_BinOp(m_Specific(Op1->getOperand(0)), m_Value(Other))))
  3602 |       return std::make_pair(Op1->getOperand(1), Other);
  3603 |     if (match(Op2, m_c_BinOp(m_Specific(Op1->getOperand(1)), m_Value(Other))))
  3604 |       return std::make_pair(Op1->getOperand(0), Other);
  3605 |     break;
  3606 |   }
  3607 |   case Instruction::Sub:
  3608 |     if (Op1->getOperand(0) == Op2->getOperand(0))
  3609 |       return getOperands(1);
  3610 |     if (Op1->getOperand(1) == Op2->getOperand(1))
  3611 |       return getOperands(0);
  3612 |     break;
  3613 |   case Instruction::Mul: {
  3614 |     // invertible if A * B == (A * B) mod 2^N where A, and B are integers
  3615 |     // and N is the bitwdith.  The nsw case is non-obvious, but proven by
  3616 |     // alive2: https://alive2.llvm.org/ce/z/Z6D5qK
