  3618 |     auto *OBO2 = cast<OverflowingBinaryOperator>(Op2);
  3619 |     if ((!OBO1->hasNoUnsignedWrap() || !OBO2->hasNoUnsignedWrap()) &&
  3620 |         (!OBO1->hasNoSignedWrap() || !OBO2->hasNoSignedWrap()))
  3621 |       break;
  3622 | 
  3623 |     // Assume operand order has been canonicalized
  3624 |     if (Op1->getOperand(1) == Op2->getOperand(1) &&
  3625 |         isa<ConstantInt>(Op1->getOperand(1)) &&
  3626 |         !cast<ConstantInt>(Op1->getOperand(1))->isZero())
  3627 |       return getOperands(0);
  3628 |     break;
  3629 |   }
  3630 |   case Instruction::Shl: {
