  9527 |   if (LHS == RHS)
  9528 |     return LHSIsTrue;
  9529 | 
  9530 |   // Match not
  9531 |   bool InvertRHS = false;
  9532 |   if (match(RHS, m_Not(m_Value(RHS)))) {
  9533 |     if (LHS == RHS)
  9534 |       return !LHSIsTrue;
  9535 |     InvertRHS = true;
  9536 |   }
  9537 | 
  9538 |   if (const ICmpInst *RHSCmp = dyn_cast<ICmpInst>(RHS)) {
  9539 |     if (auto Implied = isImpliedCondition(
  9540 |             LHS, RHSCmp->getCmpPredicate(), RHSCmp->getOperand(0),
  9541 |             RHSCmp->getOperand(1), DL, LHSIsTrue, Depth))
  9542 |       return InvertRHS ? !*Implied : *Implied;
  9543 |     return std::nullopt;
  9544 |   }
  9545 | 
  9546 |   const Value *V;
  9547 |   if (match(RHS, m_NUWTrunc(m_Value(V)))) {
  9548 |     if (auto Implied = isImpliedCondition(LHS, CmpInst::ICMP_NE, V,
  9549 |                                           ConstantInt::get(V->getType(), 0), DL,
  9550 |                                           LHSIsTrue, Depth))
  9551 |       return InvertRHS ? !*Implied : *Implied;
  9552 |     return std::nullopt;
  9553 |   }
  9554 | 
  9555 |   if (Depth == MaxAnalysisRecursionDepth)
  9556 |     return std::nullopt;
  9557 | 
  9558 |   // LHS ==> (RHS1 || RHS2) if LHS ==> RHS1 or LHS ==> RHS2
  9559 |   // LHS ==> !(RHS1 && RHS2) if LHS ==> !RHS1 or LHS ==> !RHS2
  9560 |   const Value *RHS1, *RHS2;
